arguments.new_string:
.subtitle {
    font-size: 12px;
    color: var(--neon-orange);
    max-width: 500px;
    margin: 10px auto;
    padding: 8px 20px;
    border: 1px solid var(--neon-orange);
    background: rgba(255,102,0,0.05);
    position: relative;
    animation: glitch-skew 3s infinite, borderFlicker 4s infinite;
    font-family: 'Share Tech Mono', monospace;
    letter-spacing: 1px;
}

.subtitle::before, .subtitle::after {
    content: '◆';
    position: absolute;
    color: var(--neon-orange);
    font-size: 12px;
    top: 50%;
    transform: translateY(-50%);
    animation: glitch-blink 2s infinite;
}

.subtitle::before { 
    left: 8px; 
    animation-delay: 0s;
}
.subtitle::after { 
    right: 8px; 
    animation-delay: 0.5s;
}

/* 故障艺术效果 */
.subtitle-glitch {
    position: relative;
    display: inline-block;
}

.subtitle-glitch::before,
.subtitle-glitch::after {
    content: attr(data-text);
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
}

.subtitle-glitch::before {
    color: var(--neon-pink);
    animation: glitch-1 2s infinite linear alternate-reverse;
    clip-path: polygon(0 0, 100% 0, 100% 30%, 0 30%);
    opacity: 0.8;
}

.subtitle-glitch::after {
    color: var(--neon-cyan);
    animation: glitch-2 3s infinite linear alternate-reverse;
    clip-path: polygon(0 70%, 100% 70%, 100% 100%, 0 100%);
    opacity: 0.8;
}

@keyframes glitch-skew {
    0%, 90%, 100% { transform: skew(0deg); }
    91% { transform: skew(-1deg); }
    92% { transform: skew(1deg); }
    93% { transform: skew(0deg); }
}

@keyframes glitch-blink {
    0%, 90%, 100% { opacity: 1; }
    91% { opacity: 0.3; }
    92% { opacity: 1; }
    93% { opacity: 0.5; }
    94% { opacity: 1; }
}

@keyframes borderFlicker {
    0%, 100% { border-color: var(--neon-orange); opacity: 1; }
    50% { border-color: rgba(255,102,0,0.3); opacity: 0.9; }
    92% { border-color: rgba(255,0,255,0.5); }
    93% { border-color: rgba(0,255,255,0.5); }
    94% { border-color: var(--neon-orange); }
}

